 1	import * as React from 'react';
 2	import { useODFNamespaceSelector } from '@odf/core/redux';
 3	import { CommonModalProps } from '@odf/shared/modals/common';
 4	import { ModalBody } from '@odf/shared/modals/Modal';
 5	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 6	import { Modal, ModalVariant } from '@patternfly/react-core';
 7	import NamespaceStoreForm from './namespace-store-form';
 8	import '../mcg-endpoints/noobaa-provider-endpoints.scss';
 9	
10	const NamespaceStoreModal: React.FC<NamespaceStoreModalProps> = (props) => {
11	  const { t } = useCustomTranslation();
12	  const { isOpen, closeModal } = props;
13	
14	  const { odfNamespace } = useODFNamespaceSelector();
15	
16	  return (
17	    <Modal
18	      isOpen={isOpen}
19	      onClose={closeModal}
20	      variant={ModalVariant.small}
21	      title={t('Create new NamespaceStore')}
22	      hasNoBodyWrapper={true}
23	    >
24	      <div className="nb-endpoints__modal">
25	        <ModalBody>
26	          <p>
27	            {t(
28	              'Represents an underlying storage to be used as read or write target for the data in the namespace buckets.'
29	            )}
30	          </p>
31	          <NamespaceStoreForm
32	            namespace={odfNamespace}
33	            onCancel={closeModal}
34	            redirectHandler={closeModal}
35	          />
36	        </ModalBody>
37	      </div>
38	    </Modal>
39	  );
40	};
41	
42	type NamespaceStoreModalProps = CommonModalProps<{
43	  namespace: string;
44	}>;
45	
46	export default NamespaceStoreModal;

